class Solution:
    def minMaxDifference(self, num):
        s = str(num)
        best_max = num
        best_min = num
        for d1 in '0123456789':
            for d2 in '0123456789':
                t = s.replace(d1, d2)
                v = int(t)
                if v > best_max:
                    best_max = v
                if v < best_min:
                    best_min = v
        return best_max - best_min

