var minMaxDifference = function(num) {
    const s = String(num);
    let maxS = s;
    for (const ch of s) {
        if (ch !== '9') {
            maxS = s.split(ch).join('9');
            break;
        }
    }
    const minS = s.split(s[0]).join('0');
    return parseInt(maxS, 10) - parseInt(minS, 10);
};
